import { jsPDF } from "jspdf";
import 'jspdf-autotable'
import { normal, bold } from '@/assets/font/Pretendard'

import PagePath from '@/components/widget/PagePath';
import ViewRoutePopup from '@/components/popup/history/ViewRoute';
import DroneVideoPopup from '@/components/popup/common/DroneVideo';

import * as DateUtil from '@/common/DateUtil';
import * as JsonUtil from '@/common/JsonUtil';
import * as LogUtil from "@/common/LogUtil";
import * as DetectLogA from "@/rest/DetectLogA";
import * as DetectLogD from "@/rest/DetectLogD";

import AlertModal from '@/components/modal/AlertModal'

export default {
  components: {
    PagePath,
    ViewRoutePopup,
    DroneVideoPopup,
    AlertModal
  },
  data: () => ({
    alertModalParams: { isOpened: false, title: '', message: ''},

    tabView: 1,
    // pageNo: 1,
    selectedKeywordOption: null,
    keyword: null,
    keywordOptionList: [
      { label: '드론 모델', value: 'MODEL_NAME' },
      { label: '드론 ID',   value: 'DRONE_ID' }
    ],
    // rowsPerPage: '10개씩 보기',
    popupViewState: '',
    // ViewLengthList: ['10개씩 보기', '20개씩 보기', '30개씩 보기', '40개씩 보기', '50개씩 보기'],
    isPickerOpen: false,
    // isPopupOpen: false,
    datesDigital: [DateUtil.getBeforeMonth(1), DateUtil.getCurrentDate()],
    datesAnalog: [DateUtil.getBeforeMonth(1), DateUtil.getCurrentDate()],
    checkNum: [],
    selectInfo: [],
    headersDigital: [
      { sortable: false },
      { text: 'No', value: 'DETECT_LOG_D_ID', sortable: false },
      { text: '등록 드론', value: 'DRONE_NAME', sortable: false },
      { text: '드론 모델/프로토콜', value: 'MODEL_NAME', sortable: false },
      { text: '드론 ID', value: 'DRONE_ID' },
      { text: '탐지 시작 시간', value: 'DETECT_S_TIME' },
      { text: '탐지 종료 시간', value: 'DETECT_E_TIME' },
      { text: '최초 출현 방향', value: 'FIRST_AZIMUTH' },
    ],
    headersAnalog: [
      { text: 'No', value: 'DETECT_LOG_A_ID', sortable: false },
      { text: '주파수', value: 'FREQUENCY', sortable: false },
      { text: '최초 출현 방향', value: 'FIRST_AZIMUTH' },
      { text: '탐지 시작 시간', value: 'DETECT_S_TIME' },
      { text: '탐지 종료 시간', value: 'DETECT_E_TIME' },
    ],

    dataListDigital: [],
    dataListAnalog: [],

    itemsPerPageDigital: [
      { label: '10개씩 보기', value: 10 },
      { label: '20개씩 보기', value: 20 },
      { label: '30개씩 보기', value: 30 },
      { label: '40개씩 보기', value: 40 },
      { label: '50개씩 보기', value: 50 },
    ],

    isLoadingDigital: false,
    sortByDigital: null,
    sortDescDigital: null,
    optionsDigital: {},
    pageNoDigital: 1,
    numOfPagesDigital: 0,
    numOfAllDataDigital: 0,    
    rowsPerPageDigital: 10,
    selectedRowsDigital: [],

    itemsPerPageAnalog: [
      { label: '10개씩 보기', value: 10 },
      { label: '20개씩 보기', value: 20 },
      { label: '30개씩 보기', value: 30 },
      { label: '40개씩 보기', value: 40 },
      { label: '50개씩 보기', value: 50 },
    ],
    
    isLoadingAnalog: false,
    sortByAnalog: null,
    sortDescAnalog: null,
    optionsAnalog: {},
    pageNoAnalog: 1,
    numOfPagesAnalog: 0,
    numOfAllDataAnalog: 0,    
    rowsPerPageAnalog: 10,
    selectedRowsAnalog: [],
  }),
  beforeMount() {
    this.selectedKeywordOption = this.keywordOptionList[0];
    this.doSearchDigital();
  },
  computed: {
    dateRangeTextDigital() {
      return this.datesDigital.join(' ~ ');
    },
    dateRangeTextAnalog() {
      return this.datesAnalog.join(' ~ ');
    },
  },
  watch: {
    pageNoDigital: {
      handler() {
        this.doSearchDigital();
      },
      deep: true
    },
    rowsPerPageDigital: {
      handler() {
        this.pageNoDigital = 1;
        this.doSearchDigital();
      },
      deep: true
    },
    optionsDigital: {
      handler () {
        this.doSearchDigital();
      },
      deep: true,
    },
    pageNoAnalog: {
      handler() {
        this.doSearchAnalog();
      },
      deep: true
    },
    rowsPerPageAnalog: {
      handler() {
        this.pageNoAnalog = 1;
        this.doSearchAnalog();
      },
      deep: true
    },
    optionsAnalog: {
      handler () {
        this.doSearchAnalog();
      },
      deep: true,
    },
  },
  methods: {
    showAlertModal(msg) {
      this.alertModalParams = { isOpened: true, title: 'Warning', message: msg };
    },
    tabSelect(num) {
      if (this.tabView === num) return;
      else this.tabView = num;

      this.checkNum = this.selectInfo = [];

      if(this.tabView === 1) this.doSearchDigital();
      else this.doSearchAnalog();
    },
    selectList() {
      setTimeout(() => {
        this.checkNum = document.querySelectorAll('input[type="checkbox"]:checked');
      }, 100);
    },
    popupView(view, value) {
      this.checkData();
      if (view) this.popupViewState = value;
      else this.popupViewState = '';
      // this.isPopupOpen = view;
    },
    checkData() {
      this.selectInfo = [];
      this.checkNum.forEach((checked) => {
        this.dataListDigital.map((item) => {
          if (item.idx === checked.value * 1) this.selectInfo.push(item);
        });
      });
    },
    getTimestamp(timestamp) {
      return DateUtil.getTimestamp(timestamp);
    },
    getSearchOptionDigital() {
      let searchOption = {
        defaultOptions: [],
        dateOptionList: [],
        sortOptions: [{ label: null, id: 'CREATED', value: 'desc' }],
        pagingOption: { pageNo: this.pageNoDigital, pageSize: this.rowsPerPageDigital }
      }
      
      // 날짜 검색 조건
      searchOption.dateOptions = [ { id: 'CREATED', fromDate: this.datesDigital[0], toDate: this.datesDigital[1] } ];
      
      // 키워드 검색 조건
      if(this.selectedKeywordOption != null 
        && this.keyword != null 
        && this.keyword.trim().length>0
      ) {
        searchOption.keywordOptions = [{ 
          id: this.selectedKeywordOption.value, 
          value: this.keyword
        }];
      }

      // 코드 검색 조건
      // if(this.selectedLogType !== null) {
      //   searchOption.statusOptions = [ { id: 'LOG_TYPE', value: this.selectedLogType } ];
      // }
      
      // DataTable column header 클릭 시 정렬 처리
      if(this.sortByDigital != null && this.sortByDigital.length>0) { 
        searchOption.sortOptions = [];
        searchOption.sortOptions.push({ label: null, id: this.sortByDigital, value: this.sortDescDigital ? 'asc' : 'desc' });
      }
      return searchOption;
    },
    doSearchDigital() {
      // LogUtil.debug('DocAllList.doSearch(): selectedSearchOption=', this.selectedSearchOption);
      this.selectedRowsDigital = [];
      this.isLoadingDigital = true;

      let searchOption = this.getSearchOptionDigital();
      // LogUtil.debug("searchOption=", searchOption);
      // if(searchOption != null) return;
      
      DetectLogD.listBySearchOption(searchOption).then(res => {
        // LogUtil.debug("res.data=", res.data);
        if(res.data.RES_CODE>=0) {
          this.dataListDigital = res.data.ITEMS;
          if(res.data.ITEMS.length>0) {
            this.numOfAllDataDigital = res.data.ITEMS[0].COUNT;
          } else {
            this.numOfAllDataDigital = 0;
          }
          this.numOfPagesDigital = Math.ceil(this.numOfAllDataDigital / this.rowsPerPageDigital);
          // LogUtil.debug("this.numOfPages=",this.numOfPages,", this.numOfAllData=",this.numOfAllData);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
        this.isLoadingDigital = false;
      });
    },
    getSearchOptionAnalog() {
      let searchOption = {
        defaultOptions: [],
        dateOptionList: [],
        sortOptions: [{ label: null, id: 'CREATED', value: 'desc' }],
        pagingOption: { pageNo: this.pageNoAnalog, pageSize: this.rowsPerPageAnalog }
      }
      
      // 날짜 검색 조건
      searchOption.dateOptions = [ { id: 'CREATED', fromDate: this.datesAnalog[0], toDate: this.datesAnalog[1] } ];

      // 키워드 검색 조건
      // if(this.selectedSearchOption.keywordOption != null 
      //   && this.selectedSearchOption.keywordOption.id != null
      //   && this.selectedSearchOption.keyword != null
      //   && this.selectedSearchOption.keyword.length > 0
      // ) {
      //   searchOption.keywordOptions = [{ 
      //     id: this.selectedSearchOption.keywordOption.id, 
      //     value: this.selectedSearchOption.keyword
      //   }];
      // }

      // 코드 검색 조건
      // if(this.selectedLogType !== null) {
      //   searchOption.statusOptions = [ { id: 'LOG_TYPE', value: this.selectedLogType } ];
      // }
      
      // DataTable column header 클릭 시 정렬 처리
      if(this.sortByAnalog != null && this.sortByAnalog.length>0) { 
        searchOption.sortOptions = [];
        searchOption.sortOptions.push({ label: null, id: this.sortByAnalog, value: this.sortDescAnalog ? 'asc' : 'desc' });
      }
      return searchOption;
    },
    doSearchAnalog() {
      // LogUtil.debug('DocAllList.doSearch(): selectedSearchOption=', this.selectedSearchOption);
      this.selectedRowsAnalog = [];
      this.isLoadingAnalog = true;

      let searchOption = this.getSearchOptionAnalog();
      // LogUtil.debug("searchOption=", searchOption);
      // if(searchOption != null) return;
      
      DetectLogA.listBySearchOption(searchOption).then(res => {
        // LogUtil.debug("res.data=", res.data);
        if(res.data.RES_CODE>=0) {
          this.dataListAnalog = res.data.ITEMS;
          if(res.data.ITEMS.length>0) {
            this.numOfAllDataAnalog = res.data.ITEMS[0].COUNT;
          } else {
            this.numOfAllDataAnalog = 0;
          }
          this.numOfPagesAnalog = Math.ceil(this.numOfAllDataAnalog / this.rowsPerPageAnalog);
          // LogUtil.debug("this.numOfPages=",this.numOfPages,", this.numOfAllData=",this.numOfAllData);
        } else {
          this.showAlertModal(res.data.RES_MSG);
        }
      }).catch(e => {
        LogUtil.error("error=", e);
        this.showAlertModal(e);
      }).finally(() => {
        this.isLoadingAnalog = false;
      });
    },
    doExcelDownload() {
      let header = [];
      this.headersDigital.forEach((item, index)=>{
        if(index>0) header.push(item.text);
      });
      // LogUtil.debug("header=", header);

      let dataList = [];
      this.dataListDigital.forEach((item)=>{
        let row = {};
        this.headersDigital.forEach((header, col)=>{
          if(col !== 0) {
            switch(col) {
              case 5: 
              case 6: row[header.text] = DateUtil.getCurrentTimestamp(item[header.value]); break;
              default: row[header.text] = item[header.value]; break;
            }
          }
        });
        dataList.push(row);
      });
      JsonUtil.excelDownload(header, dataList, `디지털탐지_${DateUtil.getCurrentTimestampWithNoDelimeter()}`);
    },
    doPdfDownload() {
      let colList = [];
      let rowList = [];
      
      this.headersDigital.forEach((header, c)=>{
        if(c>0) colList.push({ title: header.text, dataKey: header.value });
      });

      this.dataListDigital.forEach((item, r)=>{
        let data = {};
        data[this.headersDigital[1].value] = this.dataListDigital[r].DETECT_LOG_D_ID;
        data[this.headersDigital[2].value] = this.dataListDigital[r].DRONE_NAME;
        data[this.headersDigital[3].value] = this.dataListDigital[r].MODEL_NAME + '/' + this.dataListDigital[r].PROTOCOL;
        data[this.headersDigital[4].value] = this.dataListDigital[r].DRONE_ID;
        data[this.headersDigital[5].value] = DateUtil.getCurrentTimestamp(this.dataListDigital[r].DETECT_S_TIME);
        data[this.headersDigital[6].value] = DateUtil.getCurrentTimestamp(this.dataListDigital[r].DETECT_E_TIME);
        data[this.headersDigital[7].value] = this.dataListDigital[r].FIRST_AZIMUTH;
        rowList.push(data);
      });

      let doc = new jsPDF();
      doc.addFileToVFS('Pretendard-Regular-normal.ttf', normal);
      doc.addFont('Pretendard-Regular-normal.ttf', 'Pretendard-Regular', 'normal');
      doc.setFont('Pretendard-Regular');
      // doc.setFontType('bold');
      doc.autoTable(colList, rowList, {
          theme: 'grid',
          styles: {
              font: 'Pretendard-Regular',
              fontStyle: 'normal'
          },
          headerStyles: {
              fontSize: 15,
              font: 'Pretendard-Regular',
              fontStyle: 'normal'
          }
      });

      doc.setProperties({
        title: `디지털탐지 ${ DateUtil.getCurrentDate() }`,
      });
      doc.save(`디지털탐지_${ DateUtil.getCurrentTimestampWithNoDelimeter() }.pdf`);
    },
  },
};