<template>
    <v-container>
        <PagePath />
        <div class="content">
            <ul class="tab_option">
                <li @click="tabSelect(1)">
                    <v-btn color="primary" :outlined="tabView !== 1" rounded>디지털 탐지</v-btn>
                </li>
                <li @click="tabSelect(2)">
                    <v-btn color="primary" :outlined="tabView === 1" rounded>아날로그 탐지</v-btn>
                </li>
            </ul>
            <!-- 디지털 탐지 -->
            <div v-if="tabView === 1">
                <div class="list_options">
                    <div class="search_area">
                        <v-select
                            outlined
                            return-object
                            v-model="selectedKeywordOption"
                            :items="keywordOptionList"
                            item-text="label"
                            item-value="value"
                            placeholder="드론 모델"
                            hide-details
                            class="white"
                        />
                        <v-text-field v-model="keyword" outlined hide-details class="white" @keydown.enter="doSearchDigital" />
                    </div>
                    <div class="btn_area">
                        <span class="txt_term">기 간</span>
                        <v-menu
                            ref="menu"
                            v-model="isPickerOpen"
                            :close-on-content-click="false"
                            :return-value.sync="datesDigital"
                            transition="scale-transition"
                            offset-y
                            min-width="auto"
                        >
                            <template v-slot:activator="{ on, attrs }">
                                <div>
                                    <v-text-field
                                        v-model="dateRangeTextDigital"
                                        v-bind="attrs"
                                        v-on="on"
                                        outlined
                                        prepend-inner-icon="mdi-calendar"
                                        readonly
                                        hide-details
                                        class="white"
                                    />
                                </div>
                            </template>
                            <v-date-picker v-model="datesDigital" range no-title>
                                <v-spacer></v-spacer>
                                <v-btn text color="primary" @click="isPickerOpen = false"> 취소 </v-btn>
                                <v-btn text color="primary" @click="$refs.menu.save(datesDigital)"> 확인 </v-btn>
                            </v-date-picker>
                        </v-menu>
                        <v-btn elevation="3" color="primary" class="btn_search" outlined @click="doSearchDigital">검색</v-btn>
                        <v-btn
                            elevation="3"
                            color="primary"
                            class="btn_route"
                            :disabled="checkNum.length === 0"
                            outlined
                            @click="popupView(true, 'path')"
                            >경로보기</v-btn
                        >
                        <v-btn
                            elevation="3"
                            color="primary"
                            class="btn_play"
                            :disabled="checkNum.length === 0"
                            outlined
                            @click="popupView(true, 'video')"
                            >재생</v-btn
                        >
                        <!-- <button class="btn_xls" :disabled="checkNum.length === 0" @click="checkData()"></button>
                        <button class="btn_pdf" :disabled="checkNum.length === 0" @click="checkData()"></button> -->
                        <button class="btn_xls" :disabled="checkNum.length === 0" @click="doExcelDownload()"></button>
                        <button class="btn_pdf" :disabled="checkNum.length === 0" @click="doPdfDownload()"></button>
                        
                        <v-select
                            outlined
                            v-model="rowsPerPageDigital"
                            :items="itemsPerPageDigital"
                            item-text="label"
                            item-value="value"
                            placeholder="10개씩 보기"
                            hide-details
                            class="white view_length"
                        />
                    </div>
                </div>
                <v-data-table
                    v-model="selectedRowsDigital"
                    :loading="isLoadingDigital"
                    item-key="DETECT_LOG_D_ID"
                    checkbox-color="primary"
                    :headers="headersDigital"
                    :items="dataListDigital"
                    :items-per-page="rowsPerPageDigital"
                    no-data-text="데이터가 존재하지 않습니다."
                    hide-default-footer
                    :server-items-length="numOfAllDataDigital"
                    :options.sync="optionsDigital"
                    :sort-by.sync="sortByDigital"
                    :sort-desc.sync="sortDescDigital"
                >
                    <template #item="{ item }">
                        <tr>
                            <td>
                                <v-checkbox :value="item.idx" @click="selectList()" />
                            </td>
                            <td>{{ item.DETECT_LOG_D_ID }}</td>
                            <td>{{ item.DRONE_NAME }}</td>
                            <td>{{ item.MODEL_NAME }} / {{ item.PROTOCOL }}</td>
                            <td>{{ item.DRONE_ID }}</td>
                            <td>{{ getTimestamp(item.DETECT_S_TIME) }}</td>
                            <td>{{ getTimestamp(item.DETECT_E_TIME) }}</td>
                            <td>{{ item.FIRST_AZIMUTH }}</td>
                        </tr>
                    </template>
                </v-data-table>
                <v-col class="pagination" v-if="tabView === 1">
                  <v-pagination v-model="pageNoDigital" :length="numOfPagesDigital" :total-visible="rowsPerPageDigital" />
              </v-col>
            </div>
            <!-- // 디지털 탐지 -->
            <!-- 아날로그 탐지 -->
            <div v-else>
                <div class="list_options">
                    <div class="btn_area analog">
                        <span class="txt_term">기 간</span>
                        <v-menu
                            ref="menu"
                            v-model="isPickerOpen"
                            :close-on-content-click="false"
                            :return-value.sync="datesAnalog"
                            transition="scale-transition"
                            offset-y
                            min-width="auto"
                        >
                            <template v-slot:activator="{ on, attrs }">
                                <div>
                                    <v-text-field
                                        v-model="dateRangeTextAnalog"
                                        v-bind="attrs"
                                        v-on="on"
                                        outlined
                                        prepend-inner-icon="mdi-calendar"
                                        readonly
                                        hide-details
                                        class="white"
                                    />
                                </div>
                            </template>
                            <v-date-picker v-model="datesAnalog" range no-title>
                                <v-spacer></v-spacer>
                                <v-btn text color="primary" @click="isPickerOpen = false"> 취소 </v-btn>
                                <v-btn text color="primary" @click="$refs.menu.save(datesAnalog)"> 확인 </v-btn>
                            </v-date-picker>
                        </v-menu>
                        <v-btn elevation="3" color="primary" class="btn_search" outlined @click="doSearchAnalog">검색</v-btn>
                        <v-select
                            outlined
                            v-model="rowsPerPageAnalog"
                            :items="itemsPerPageAnalog"
                            item-text="label"
                            item-value="value"
                            placeholder="10개씩 보기"
                            hide-details
                            class="white view_length"
                        />
                    </div>
                </div>
                <v-data-table
                  v-model="selectedRowsAnalog"
                  :loading="isLoadingAnalog"
                  item-key="DETECT_LOG_A_ID"
                  checkbox-color="primary"
                  :headers="headersAnalog"
                  :items="dataListAnalog"
                  :items-per-page="rowsPerPageAnalog"
                  no-data-text="데이터가 존재하지 않습니다."
                  hide-default-footer
                  :server-items-length="numOfAllDataAnalog"
                  :options.sync="optionsAnalog"
                  :sort-by.sync="sortByAnalog"
                  :sort-desc.sync="sortDescAnalog"
                >
                    <template #item="{ item }">
                        <tr>
                            <td>{{ item.DETECT_LOG_A_ID }}</td>
                            <td>{{ item.FREQUENCY }}</td>
                            <td>{{ item.FIRST_AZIMUTH }}</td>
                            <td>{{ getTimestamp(item.DETECT_S_TIME) }}</td>
                            <td>{{ getTimestamp(item.DETECT_E_TIME) }}</td>
                        </tr>
                    </template>
                </v-data-table>
                <!-- // 아날로그 탐지 -->
                <v-col class="pagination" v-if="tabView === 2">
                  <v-pagination v-model="pageNoAnalog" :length="numOfPagesAnalog" :total-visible="rowsPerPageAnalog" />
                </v-col>
            </div>
        </div>
        <ViewRoutePopup v-if="popupViewState === 'path'" :selectInfo="selectInfo" :popupViewState="popupViewState" @popupClose="popupView" />
        <DroneVideoPopup v-if="popupViewState === 'video'" @popupClose="popupView" />

        <AlertModal :params="alertModalParams"></AlertModal>
    </v-container>
</template>

<script>
import Obj from './DetectionList.js';
export default Obj;
</script>

<style lang="scss" scoped>
.content {
    .tab_option {
        padding-left: 0;
        li {
            display: inline-block;
            button {
                height: 45px;
                padding: 0 21px;
                font: {
                    size: 18px;
                    weight: 600;
                }
            }
            & + li {
                margin-left: 5px;
            }
        }
    }
    .list_options {
        @include hCenterAlign();
        margin-top: 30px;
        .search_area {
            overflow: hidden;
            width: 280px;
            margin-right: 18px;
            .v-select {
                float: left;
                width: 120px;
                margin-right: 5px;
            }
        }
        .btn_area {
            @include hCenterAlign();
            .txt_term {
                width: 40px;
                margin-right: 7px;
                font {
                    size: 12px;
                }
                color: $color-main02;
            }
            .btn_search {
                width: 80px;
                margin-left: 5px;
            }
            .btn_route {
                width: 92px;
                margin-left: 19px;
            }
            .btn_play {
                width: 66px;
                margin-left: 10px;
            }
            & > button {
                width: 30px;
                height: 36px;
                &.btn_xls {
                    margin-left: 24px;
                    background: url('@/assets/history/btn_xls_on.svg') no-repeat 0 0;
                    &:disabled {
                        background-image: url('@/assets/history/btn_xls_off.svg');
                    }
                }
                &.btn_pdf {
                    margin-left: 10px;
                    background: url('@/assets/history/btn_pdf_on.svg') no-repeat 0 0;
                    &:disabled {
                        background-image: url('@/assets/history/btn_pdf_off.svg');
                    }
                }
            }
            .view_length {
                width: 150px;
                margin-left: 10px;
            }
            &.analog {
                width: 100%;
                .view_length {
                    margin-left: 590px;
                }
            }
        }
    }
    .v-data-table {
        margin-top: 33px;
    }
    .pagination {
        padding: 0;
        margin-top: 50px;
    }
}
</style>
